import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { Rsvp, RsvpStatus } from '../../core/models';

/**
 * GatherUp "My Events" — the caller's RSVPs and their statuses.
 * Mock data is a signal<Rsvp[]>; service_agent wires ApiService.myEvents().
 */
@Component({
  selector: 'app-my-events',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './my-events.component.html',
  styleUrl: './my-events.component.css',
})
export class MyEventsComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly rsvps = signal<Rsvp[]>([
    {
      id: 'r1', eventId: 'e1', userId: 'me', status: 'confirmed',
      event: {
        id: 'e1', venueId: 'v1', title: 'Indie Synth Night', description: '',
        category: 'Music', startsAt: '2026-07-18T20:00:00.000Z', endsAt: '2026-07-18T23:00:00.000Z',
        capacity: 120, venue: { id: 'v1', name: 'The Warehouse', address: '12 Dock Road', defaultCapacity: 150 },
      },
    },
    {
      id: 'r2', eventId: 'e3', userId: 'me', status: 'waitlist',
      event: {
        id: 'e3', venueId: 'v1', title: 'Intro to Watercolor', description: '',
        category: 'Workshop', startsAt: '2026-07-22T18:30:00.000Z', endsAt: '2026-07-22T20:30:00.000Z',
        capacity: 1, venue: { id: 'v1', name: 'The Warehouse', address: '12 Dock Road', defaultCapacity: 150 },
      },
    },
    {
      id: 'r3', eventId: 'e5', userId: 'me', status: 'checkedIn',
      event: {
        id: 'e5', venueId: 'v1', title: 'Jazz & Wine Tasting', description: '',
        category: 'Music', startsAt: '2026-07-30T19:00:00.000Z', endsAt: '2026-07-30T22:00:00.000Z',
        capacity: 60, venue: { id: 'v1', name: 'The Warehouse', address: '12 Dock Road', defaultCapacity: 150 },
      },
    },
  ]);

  ngOnInit(): void {
    // service_agent: this.api.myEvents().subscribe(r => this.rsvps.set(r));
  }

  badge(status: RsvpStatus): { cls: string; label: string } {
    switch (status) {
      case 'confirmed': return { cls: 'badge-ok', label: 'Confirmed' };
      case 'checkedIn': return { cls: 'badge-info', label: 'Checked in' };
      case 'waitlist': return { cls: 'badge-warn', label: 'Waitlisted' };
      default: return { cls: 'badge-muted', label: 'Cancelled' };
    }
  }

  when(iso?: string): string {
    if (!iso) return '';
    return new Date(iso).toLocaleString(undefined, {
      weekday: 'short', month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit',
    });
  }
}
